+    state->inner = inner;
+    state->make_fn = make_fn;
+    state->factory_data = factory_data;
+    state->reconnect_count = 0;
+    state->max_reconnects = max_reconnects;
+    svc->poll_ready = reconnect_poll_ready;
+    svc->call = reconnect_call;
+    svc->state = state;
+}
